struct ContentView: View {

    // MARK: - State Properties
    @State private var registrationStateText: String = "Unknown"
    @State private var devices = []

    var body: some View {
        VStack(spacing: 16) {
            Text("Registration Status: \(registrationStateText)")
                .padding()

            Text("Devices: \(devices.count)")
                .padding()

            Button("Register") {
                configureWearables()
                startRegistration()
                observeWearables()

            }
            .buttonStyle(.borderedProminent)

            Button("Unregister") {
                startUnregistration()
                observeWearables()
            }
            .buttonStyle(.bordered)
        }
        .padding()
        .onAppear {
            configureWearables()
            observeWearables()
        }
    }

