        }
    }

    // MARK: - Registration
    func startRegistration() {
        do {
            try Wearables.shared.startRegistration()
            print("Registration started")
        } catch {
            print("Error starting registration: \(error)")
        }
    }

    func startUnregistration() {
        do {
            try Wearables.shared.startUnregistration()
            print("Unregistration started")
        } catch {
            print("Error starting unregistration: \(error)")
        }
    }

    // MARK: - Observation
    func observeWearables() {
        let wearables = Wearables.shared

        Task {
            for await devices in wearables.devicesStream() {
              // Update the list of available glasses
                print("devices ->\(devices)")
